"""matplotlib.quiver — quiver and barbs plot stubs."""

from matplotlib.artist import Artist
import numpy as _np


class QuiverKey(Artist):
    def __init__(self, Q, X, Y, U, label, **kwargs):
        super().__init__()
        self.Q = Q
        self.X = X
        self.Y = Y
        self.U = U
        self.label = label


class Quiver(Artist):
    def __init__(self, ax, *args, **kwargs):
        super().__init__()
        self.ax = ax

    def set_UVC(self, U, V, C=None): pass
    def set_offsets(self, offsets): pass
    def get_datalim(self, transData): return None


class Barbs(Artist):
    def __init__(self, ax, *args, **kwargs):
        super().__init__()
        self.ax = ax

    def set_UVC(self, U, V, C=None): pass
    def set_offsets(self, offsets): pass
